export type MediaStatus = "draft" | "active" | "deprecated" | "archived";
export type MediaVisibility = "public" | "internal" | "private" | "hidden";
export type MediaType = "image" | "video" | "audio" | "diagram" | "screenshot" | "infographic" | "pdf" | "document" | "thumbnail" | "transcript" | "subtitle" | "presentation" | "download" | "source-file";
export type ConsentStatus = "not-required" | "required" | "granted" | "denied" | "unknown";
export type MediaAsset = {
    id: string;
    type: MediaType;
    title: string;
    status: MediaStatus;
    visibility: MediaVisibility;
    source: string;
    canonicalUrl?: string;
    description?: string;
    altText?: string;
    caption?: string;
    language?: string;
    fileName?: string;
    mimeType?: string;
    fileSize?: number;
    width?: number;
    height?: number;
    duration?: number;
    thumbnailId?: string;
    transcriptId?: string;
    subtitleIds?: string[];
    author?: string;
    creator?: string;
    owner?: string;
    license?: string;
    copyright?: string;
    credit?: string;
    relatedObjectIds?: string[];
    relatedEntityIds?: string[];
    citationIds?: string[];
    consentStatus?: ConsentStatus;
    privacyLevel?: "public" | "sensitive" | "confidential";
    createdAt: string;
    updatedAt: string;
};
